import test from "node:test";
import assert from "node:assert/strict";

import { linkAbort } from "../src/abort-link.mjs";
import { ConnectionService } from "../src/connection-service.mjs";

test("linking an already-cancelled parent preserves cancellation immediately", () => {
  const parent = new AbortController();
  const reason = new Error("drain already active");
  parent.abort(reason);

  const linked = linkAbort(parent.signal);
  assert.equal(linked.signal.aborted, true);
  assert.equal(linked.signal.reason, reason);
  linked.dispose();
});

test("a pre-cancelled connection never opens its transport", async () => {
  const parent = new AbortController();
  const reason = new Error("deployment drain");
  parent.abort(reason);
  let opens = 0;
  const transport = {
    name: "should-not-open",
    async open() {
      opens += 1;
    },
    async receive() {
      return null;
    }
  };

  const service = new ConnectionService();
  await assert.rejects(service.connect(transport, parent.signal), (error) => error === reason);
  assert.equal(opens, 0);
});
